import React from 'react';
import { AppBar, Toolbar, Typography, Button, Box, Badge } from '@mui/material';
import { Link, useNavigate } from 'react-router-dom';
import { Notifications as NotificationsIcon } from '@mui/icons-material';
import { useAuth } from '../context/AuthContext';
import logo from '../assets/logo.jpeg';

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <AppBar position="static" sx={{ bgcolor: '#1a5276' }}>
      <Toolbar>
        {/* الشعار + الاسم */}
        <Box 
          component={Link} 
          to="/" 
          sx={{ 
            flexGrow: 1, 
            display: 'flex', 
            alignItems: 'center', 
            gap: 1.5,
            textDecoration: 'none',
            color: 'white'
          }}
        >
          <img 
            src={logo} 
            alt="وصّال" 
            className="logo-shadow"
            style={{ 
              height: 42, 
              width: 42, 
              borderRadius: '50%', 
              objectFit: 'cover',
              border: '2px solid rgba(255,255,255,0.3)'
            }} 
          />
          <Box>
            <Typography 
              variant="h5" 
              sx={{ 
                fontWeight: 'bold',
                fontFamily: '"Cairo", sans-serif',
                lineHeight: 1.2
              }}
            >
              وصّال
            </Typography>
            <Typography 
              variant="caption" 
              sx={{ 
                opacity: 0.9,
                fontSize: '0.75rem'
              }}
            >
              جامعة الشمال الخاصة
            </Typography>
          </Box>
        </Box>

        <Box sx={{ display: 'flex', gap: 0.5 }}>
          <Button color="inherit" component={Link} to="/" className="btn-hover">
            الرئيسية
          </Button>
          <Button color="inherit" component={Link} to="/about" className="btn-hover">
            من نحن
          </Button>
          <Button color="inherit" component={Link} to="/contact" className="btn-hover">
            تواصل معنا
          </Button>

          {user ? (
            <>
              <Button color="inherit" component={Link} to="/notifications" className="btn-hover">
                <Badge badgeContent={0} color="error">
                  <NotificationsIcon />
                </Badge>
              </Button>
              <Button color="inherit" component={Link} to="/my-products" className="btn-hover">
                منتجاتي
              </Button>
              <Button color="inherit" component={Link} to="/add-product" className="btn-hover">
                إضافة
              </Button>
              {user.role === 'admin' && (
                <Button color="inherit" component={Link} to="/admin" className="btn-hover">
                  لوحة التحكم
                </Button>
              )}
              <Button color="inherit" onClick={handleLogout} className="btn-hover">
                خروج
              </Button>
            </>
          ) : (
            <>
              <Button color="inherit" component={Link} to="/login" className="btn-hover">
                تسجيل دخول
              </Button>
              <Button color="inherit" component={Link} to="/register" className="btn-hover">
                حساب جديد
              </Button>
            </>
          )}
        </Box>
      </Toolbar>
    </AppBar>
  );
}
